/**
 * Northline Icons — Gallery Script
 * script.js
 *
 * Requires: icons-data.js (generated by docs/build.js)
 * window.ICONS_DATA  — array of icon objects
 * window.ICONS_META  — library metadata
 */

"use strict";

/* ── State ──────────────────────────────────────────────────────────────── */
const state = {
  icons:           [],
  filtered:        [],
  query:           "",
  activeCategory:  "all",
};

/* ── DOM refs ────────────────────────────────────────────────────────────── */
const $ = (id) => document.getElementById(id);

const DOM = {
  searchInput:    $("searchInput"),
  searchClear:    $("searchClear"),
  filterBar:      $("filterBar"),
  iconGrid:       $("iconGrid"),
  resultsCount:   $("resultsCount"),
  clearFiltersBtn:$("clearFiltersBtn"),
  emptyState:     $("emptyState"),
  emptyReset:     $("emptyReset"),
  toastContainer: $("toastContainer"),
  themeToggle:    $("themeToggle"),
  modalOverlay:   $("modalOverlay"),
  modalClose:     $("modalClose"),
  modalPreview:   $("modalPreview"),
  modalIconName:  $("modalIconName"),
  modalCategory:  $("modalCategory"),
  modalTags:      $("modalTags"),
  modalCode:      $("modalCode"),
  modalCopySvg:   $("modalCopySvg"),
  modalCopyName:  $("modalCopyName"),
  modalDownload:  $("modalDownload"),

  // Stats
  statIcons:      $("statIcons"),
  statCategories: $("statCategories"),
  statUpdated:    $("statUpdated"),
  heroCount:      $("heroCount"),
  logoVersion:    $("logoVersion"),
  footerVersion:  $("footerVersion"),
};

/* Active modal icon */
let modalIcon = null;

/* ── Init ────────────────────────────────────────────────────────────────── */
function init() {
  if (!window.ICONS_DATA || !window.ICONS_META) {
    showFatalError();
    return;
  }

  state.icons    = window.ICONS_DATA;
  state.filtered = [...state.icons];

  populateStats();
  buildFilters();
  renderIcons(state.filtered);
  attachEvents();
  restoreTheme();
  observeToolbar();
}

/* ── Stats ───────────────────────────────────────────────────────────────── */
function populateStats() {
  const m = window.ICONS_META;
  if (!m) return;

  const count = m.totalIcons || state.icons.length;
  const cats  = m.totalCategories || Object.keys(m.categories || {}).length;

  if (DOM.statIcons)      DOM.statIcons.textContent      = count;
  if (DOM.statCategories) DOM.statCategories.textContent = cats;
  if (DOM.heroCount)      DOM.heroCount.textContent       = count;
  if (DOM.logoVersion)    DOM.logoVersion.textContent     = `v${m.version || "1.0.0"}`;
  if (DOM.footerVersion)  DOM.footerVersion.textContent   = `v${m.version || "1.0.0"}`;

  if (DOM.statUpdated && m.generatedAt) {
    const d = new Date(m.generatedAt);
    DOM.statUpdated.textContent = d.toLocaleDateString("en-US", { month: "long", year: "numeric" });
  }
}

/* ── Build category filters ──────────────────────────────────────────────── */
function buildFilters() {
  if (!DOM.filterBar) return;

  const categories = ["all", ...getCategories()];
  const frag = document.createDocumentFragment();

  categories.forEach((cat) => {
    const count = cat === "all"
      ? state.icons.length
      : state.icons.filter((i) => i.category === cat).length;

    const btn = document.createElement("button");
    btn.className  = "filter-btn" + (cat === "all" ? " active" : "");
    btn.dataset.cat = cat;
    btn.setAttribute("aria-pressed", cat === "all" ? "true" : "false");
    btn.innerHTML  = `${capitalise(cat)} <span class="filter-count">${count}</span>`;

    btn.addEventListener("click", () => selectCategory(cat));
    frag.appendChild(btn);
  });

  DOM.filterBar.appendChild(frag);
}

function getCategories() {
  const seen = new Set();
  return state.icons
    .map((i) => i.category)
    .filter((c) => { if (seen.has(c)) return false; seen.add(c); return true; })
    .sort();
}

/* ── Render ───────────────────────────────────────────────────────────────── */
function renderIcons(icons) {
  if (!DOM.iconGrid) return;

  DOM.iconGrid.innerHTML = "";

  const isEmpty = icons.length === 0;
  DOM.emptyState.hidden  = !isEmpty;
  DOM.iconGrid.hidden    = isEmpty;

  updateResultsCount(icons.length);

  if (isEmpty) return;

  const frag = document.createDocumentFragment();

  icons.forEach((icon) => {
    const card = buildCard(icon);
    frag.appendChild(card);
  });

  DOM.iconGrid.appendChild(frag);
}

function buildCard(icon) {
  const card = document.createElement("div");
  card.className    = "icon-card";
  card.role         = "listitem";
  card.tabIndex     = 0;
  card.title        = icon.name;
  card.dataset.name = icon.name;

  /* SVG preview — sanitised inline render */
  const svgEl = parseSVG(icon.svg);
  svgEl && svgEl.setAttribute("aria-hidden", "true");

  card.innerHTML = `
    <div class="icon-preview" aria-hidden="true"></div>
    <span class="icon-name">${escHtml(icon.name)}</span>
    <div class="icon-card-overlay" aria-hidden="true">
      <button class="overlay-btn overlay-btn-primary" data-action="copy-svg"   tabindex="-1">Copy SVG</button>
      <button class="overlay-btn overlay-btn-secondary" data-action="copy-name" tabindex="-1">Copy name</button>
      <button class="overlay-btn overlay-btn-secondary" data-action="download"  tabindex="-1">Download</button>
    </div>
  `;

  if (svgEl) card.querySelector(".icon-preview").appendChild(svgEl);

  /* Overlay button clicks (stop propagation so card click doesn't also fire) */
  card.querySelectorAll("[data-action]").forEach((btn) => {
    btn.addEventListener("click", (e) => {
      e.stopPropagation();
      handleCardAction(btn.dataset.action, icon);
    });
  });

  /* Card click → open modal */
  card.addEventListener("click", () => openModal(icon));

  /* Keyboard: Enter/Space opens modal */
  card.addEventListener("keydown", (e) => {
    if (e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      openModal(icon);
    }
  });

  return card;
}

/* ── Filter & Search ─────────────────────────────────────────────────────── */
function filterIcons() {
  const q   = state.query.trim().toLowerCase();
  const cat = state.activeCategory;

  state.filtered = state.icons.filter((icon) => {
    const catMatch = cat === "all" || icon.category === cat;
    if (!catMatch) return false;
    if (!q) return true;

    return (
      icon.name.toLowerCase().includes(q) ||
      icon.category.toLowerCase().includes(q) ||
      (icon.tags && icon.tags.some((t) => t.toLowerCase().includes(q)))
    );
  });

  renderIcons(state.filtered);
  updateClearBtn();
}

function selectCategory(cat) {
  state.activeCategory = cat;

  DOM.filterBar.querySelectorAll(".filter-btn").forEach((btn) => {
    const isActive = btn.dataset.cat === cat;
    btn.classList.toggle("active", isActive);
    btn.setAttribute("aria-pressed", isActive ? "true" : "false");
  });

  filterIcons();
}

function updateResultsCount(count) {
  if (!DOM.resultsCount) return;
  const total = state.icons.length;
  if (state.query === "" && state.activeCategory === "all") {
    DOM.resultsCount.textContent = `${total} icons`;
  } else {
    DOM.resultsCount.textContent = `${count} of ${total} icons`;
  }
}

function updateClearBtn() {
  const active = state.query !== "" || state.activeCategory !== "all";
  if (DOM.clearFiltersBtn) DOM.clearFiltersBtn.hidden = !active;
}

function resetSearch() {
  state.query          = "";
  state.activeCategory = "all";
  if (DOM.searchInput) { DOM.searchInput.value = ""; DOM.searchClear.hidden = true; }

  DOM.filterBar.querySelectorAll(".filter-btn").forEach((btn) => {
    const isAll = btn.dataset.cat === "all";
    btn.classList.toggle("active", isAll);
    btn.setAttribute("aria-pressed", isAll ? "true" : "false");
  });

  filterIcons();
}

/* ── Actions ─────────────────────────────────────────────────────────────── */
function handleCardAction(action, icon) {
  switch (action) {
    case "copy-svg":  copySVG(icon);  break;
    case "copy-name": copyName(icon); break;
    case "download":  download(icon); break;
  }
}

async function copySVG(icon) {
  try {
    await navigator.clipboard.writeText(icon.svg);
    showToast("SVG copied to clipboard", "copy");
  } catch {
    fallbackCopy(icon.svg);
    showToast("SVG copied to clipboard", "copy");
  }
}

async function copyName(icon) {
  try {
    await navigator.clipboard.writeText(icon.name);
    showToast(`"${icon.name}" copied`, "copy");
  } catch {
    fallbackCopy(icon.name);
    showToast(`"${icon.name}" copied`, "copy");
  }
}

function download(icon) {
  const blob = new Blob([icon.svg], { type: "image/svg+xml;charset=utf-8" });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement("a");
  a.href     = url;
  a.download = `${icon.name}.svg`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  showToast(`Downloading ${icon.name}.svg`, "download");
}

function fallbackCopy(text) {
  const ta = document.createElement("textarea");
  ta.value = text;
  ta.style.cssText = "position:fixed;top:-9999px;left:-9999px";
  document.body.appendChild(ta);
  ta.select();
  document.execCommand("copy");
  document.body.removeChild(ta);
}

/* ── Modal ───────────────────────────────────────────────────────────────── */
function openModal(icon) {
  modalIcon = icon;

  const svgEl = parseSVG(icon.svg);
  DOM.modalPreview.innerHTML = "";
  if (svgEl) {
    svgEl.setAttribute("aria-hidden", "true");
    DOM.modalPreview.appendChild(svgEl);
  }

  DOM.modalIconName.textContent = icon.name;
  DOM.modalCategory.textContent = capitalise(icon.category);

  DOM.modalTags.innerHTML = (icon.tags || [])
    .map((t) => `<span class="modal-tag">${escHtml(t)}</span>`)
    .join("");

  DOM.modalCode.textContent = formatSVG(icon.svg);

  DOM.modalOverlay.hidden = false;
  document.body.style.overflow = "hidden";
  DOM.modalClose.focus();
}

function closeModal() {
  DOM.modalOverlay.hidden = true;
  document.body.style.overflow = "";
  modalIcon = null;
}

/* ── Toast ───────────────────────────────────────────────────────────────── */
function showToast(message, type = "default") {
  const iconSvg = type === "download"
    ? `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>`
    : `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><polyline points="20 6 9 17 4 12"/></svg>`;

  const toast = document.createElement("div");
  toast.className = `toast`;
  toast.innerHTML = `
    <span class="toast-icon toast-icon-${type}" aria-hidden="true">${iconSvg}</span>
    <span>${escHtml(message)}</span>
  `;

  DOM.toastContainer.appendChild(toast);

  /* Auto dismiss */
  const dismiss = () => {
    toast.classList.add("toast-exit");
    toast.addEventListener("animationend", () => toast.remove(), { once: true });
  };

  const timer = setTimeout(dismiss, 2500);
  toast.addEventListener("click", () => { clearTimeout(timer); dismiss(); });
}

/* ── Theme ───────────────────────────────────────────────────────────────── */
function restoreTheme() {
  const saved = localStorage.getItem("northline-theme");
  const preferred = window.matchMedia("(prefers-color-scheme: light)").matches ? "light" : "dark";
  setTheme(saved || preferred);
}

function setTheme(theme) {
  document.documentElement.setAttribute("data-theme", theme);
  localStorage.setItem("northline-theme", theme);
}

function toggleTheme() {
  const current = document.documentElement.getAttribute("data-theme");
  setTheme(current === "dark" ? "light" : "dark");
}

/* ── Sticky toolbar observer ─────────────────────────────────────────────── */
function observeToolbar() {
  const toolbar = document.querySelector(".toolbar");
  if (!toolbar || !("IntersectionObserver" in window)) return;

  const sentinel = document.createElement("div");
  sentinel.style.cssText = "height:1px;margin-top:-1px;pointer-events:none";
  toolbar.parentNode.insertBefore(sentinel, toolbar);

  new IntersectionObserver(
    ([entry]) => toolbar.classList.toggle("is-stuck", !entry.isIntersecting),
    { threshold: 0 }
  ).observe(sentinel);
}

/* ── Events ──────────────────────────────────────────────────────────────── */
function attachEvents() {
  /* Search */
  if (DOM.searchInput) {
    DOM.searchInput.addEventListener("input", (e) => {
      state.query = e.target.value;
      DOM.searchClear.hidden = state.query === "";
      filterIcons();
    });
  }

  if (DOM.searchClear) {
    DOM.searchClear.addEventListener("click", () => {
      DOM.searchInput.value = "";
      state.query = "";
      DOM.searchClear.hidden = true;
      DOM.searchInput.focus();
      filterIcons();
    });
  }

  /* Global keyboard shortcut: "/" focuses search */
  document.addEventListener("keydown", (e) => {
    if (e.key === "/" && document.activeElement !== DOM.searchInput) {
      e.preventDefault();
      DOM.searchInput?.focus();
    }
    if (e.key === "Escape") {
      if (!DOM.modalOverlay.hidden) closeModal();
      else if (state.query || state.activeCategory !== "all") resetSearch();
    }
  });

  /* Clear filters button */
  if (DOM.clearFiltersBtn) DOM.clearFiltersBtn.addEventListener("click", resetSearch);
  if (DOM.emptyReset)      DOM.emptyReset.addEventListener("click", resetSearch);

  /* Theme toggle */
  if (DOM.themeToggle) DOM.themeToggle.addEventListener("click", toggleTheme);

  /* Modal */
  if (DOM.modalClose)   DOM.modalClose.addEventListener("click", closeModal);
  if (DOM.modalOverlay) {
    DOM.modalOverlay.addEventListener("click", (e) => {
      if (e.target === DOM.modalOverlay) closeModal();
    });
  }

  if (DOM.modalCopySvg)  DOM.modalCopySvg.addEventListener("click",  () => modalIcon && copySVG(modalIcon));
  if (DOM.modalCopyName) DOM.modalCopyName.addEventListener("click",  () => modalIcon && copyName(modalIcon));
  if (DOM.modalDownload) DOM.modalDownload.addEventListener("click",  () => modalIcon && download(modalIcon));
}

/* ── Helpers ─────────────────────────────────────────────────────────────── */

/**
 * Parse an SVG string into a live HTMLElement.
 * Returns null on failure.
 */
function parseSVG(svgString) {
  try {
    const parser = new DOMParser();
    const doc    = parser.parseFromString(svgString, "image/svg+xml");
    const err    = doc.querySelector("parsererror");
    if (err) return null;
    const el = doc.documentElement;
    el.removeAttribute("width");
    el.removeAttribute("height");
    el.style.width  = "100%";
    el.style.height = "100%";
    return el;
  } catch {
    return null;
  }
}

/**
 * Lightly format SVG source for display in the code block.
 * Adds newlines after each tag.
 */
function formatSVG(svgString) {
  return svgString
    .replace(/>\s*</g, ">\n<")
    .replace(/^\s+|\s+$/g, "");
}

function capitalise(str) {
  if (!str) return "";
  return str.charAt(0).toUpperCase() + str.slice(1);
}

function escHtml(str) {
  return String(str)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function showFatalError() {
  document.body.innerHTML = `
    <div style="display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;gap:16px;font-family:system-ui;color:#a1a1aa;text-align:center;padding:24px">
      <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round">
        <circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/>
      </svg>
      <h2 style="color:#fafafa;font-size:20px;font-weight:600">icons-data.js not found</h2>
      <p style="max-width:380px;line-height:1.6">
        Run the build script first:<br>
        <code style="font-family:monospace;background:#27272a;padding:4px 10px;border-radius:6px;font-size:13px;display:inline-block;margin-top:8px">
          node docs/build.js
        </code>
      </p>
    </div>
  `;
}

/* ── Boot ────────────────────────────────────────────────────────────────── */
if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", init);
} else {
  init();
}
